{"procName":"dbo.stockbalances_issuedstock_fifo","body":"CREATE PROCEDURE [dbo].[StockBalances_IssuedStock_FIFO]
(
	@SourceType nvarchar(50),
	@lenhcapphat nvarchar(50),
	@phieuxuat nvarchar(50),
	@makho nvarchar(50),
	@mact nvarchar(100),
	@soluong decimal(18, 5),
	@ghichu nvarchar(max),
	@nguoitao nvarchar(50),
	@id_pyc_chitiet uniqueidentifier, -- liên kết bảng tr_phieuyeucau_chitiet
	@id_chitiet_dathang int, -- liênn kết với bảng tr_dondathang_chitiet
	@id_chitiet_lcp int -- liên kế bảng tr_lenhcapphat
)
AS
BEGIN

	--SET @makho = 'NKI';
	--SET @mact = 'NVIVA0040';
	--SET @soluong  = 5000

	DECLARE @BatchNo NVARCHAR(50);
	DECLARE @QtyInBatch DECIMAL(18, 5);
	DECLARE @UnitPrice DECIMAL(18, 5);

	DECLARE @Remain DECIMAL(18,5) = @soluong; -- GÁN SỐ LƯỢNG CÒN LẠI BAN ĐẦU BẰNG SỐ LƯỢNG CẦN XUẤT
	DECLARE @QtyToIssue DECIMAL(18,5);
	DECLARE @TransactionDate DATETIME = GETDATE();
	DECLARE @SourceId int;

	-- ĐIỀU CHỈNH LẠI MÃ KHO THEO MÃ CHI TIẾT (1 MÃ CHỈ NẰM Ở 1 KHO)
	DECLARE @makho_dieuchinh nvarchar(50);
	SET @makho_dieuchinh = dbo.ufn_GetWHSMaterial(@mact);

	DECLARE CUR CURSOR LOCAL FAST_FORWARD FOR
		SELECT A.BatchNo, A.Quantity, UT.UnitPrice
		FROM StockBalances A
		OUTER APPLY
		(
			SELECT TOP 1 T.UnitPrice, T.TransactionDate
			FROM StockTransaction T
			WHERE T.MaterialCode = A.MaterialCode
				AND T.BatchNo = A.BatchNo
				AND T.WarehouseCode = A.WarehouseCode
				AND T.SourceType IN ('IN', 'TRANSFER')
			ORDER BY T.TransactionDate
		) AS UT
		WHERE A.WarehouseCode = @makho_dieuchinh
			AND A.MaterialCode = @mact
			AND A.Quantity > 0
		ORDER BY UT.TransactionDate;
	OPEN CUR;
	FETCH NEXT FROM CUR INTO @BatchNo, @QtyInBatch, @UnitPrice;
	WHILE @@FETCH_STATUS = 0 AND @Remain > 0
	BEGIN
		-- NẾU SỐ LƯỢNG BatchNo (lô hàng) >= số lượng còn lại thì lấy hết số lượng trong lô hàng và ngược lại
		SET @QtyToIssue = CASE WHEN @Remain >= @QtyInBatch THEN @QtyInBatch ELSE @Remain END;

		-- GHI CHI TIẾT PHIẾU XUẤT
		INSERT INTO tr_ctphieuxuat 
		(
			lenhcapphat, phieuxuat, makho, mact, soluong, ghichu, ngaytao, nguoitao,
			id_pyc_chitiet, id_chitiet_dathang, id_chitiet_lcp,
			BatchNo
		)
		VALUES (
			@lenhcapphat, @phieuxuat, @makho, @mact, @QtyToIssue, @ghichu, @TransactionDate, @nguoitao,
			@id_pyc_chitiet, @id_chitiet_dathang, @id_chitiet_lcp,
			@BatchNo
		)
		SET @SourceId = SCOPE_IDENTITY();

		-- ghi giao dịch xuất kho
		INSERT INTO StockTransaction
		(
			TransactionDate, SourceType, SourceId, WarehouseCode, MaterialCode,
			BatchNo, Quantity, UnitPrice, SupplierCode, CreatedBy, Note
		)
		VALUES (
			@TransactionDate, @SourceType, @SourceId, @makho_dieuchinh, @mact,
			@BatchNo, -@QtyToIssue, @UnitPrice, null, @nguoitao, @ghichu
		)

		-- cập nhật tồn kho
		UPDATE StockBalances
		SET Quantity = Quantity - @QtyToIssue
		WHERE WarehouseCode = @makho_dieuchinh
			AND MaterialCode = @mact
			AND BatchNo = @BatchNo

		IF @id_chitiet_lcp IS NOT NULL
		BEGIN
			UPDATE tr_lenhcapphat
			SET soluong_daphat = COALESCE(soluong_daphat, 0) + @QtyToIssue,
				soluong_conlai  = soluong_conlai - @QtyToIssue
			WHERE id = @id_chitiet_lcp
		END

		IF @id_pyc_chitiet IS NOT NULL
		BEGIN
			UPDATE tr_phieuyeucau_chitiet
			SET soluong_daphat = soluong_daphat + @QtyToIssue
			WHERE id = @id_pyc_chitiet
		END

		IF @id_chitiet_dathang IS NOT NULL
		BEGIN
			-- XUẤT KHO TRẢ NHÀ CUNG CẤP
			UPDATE tr_dondathang_chitiet
			SET sl_danhan = sl_danhan - @QtyToIssue,
				sl_conlai = sl_conlai + @QtyToIssue
			WHERE id = @id_chitiet_dathang
		END

		SET @Remain = @Remain - @QtyToIssue; -- CẬP NHẬT SỐ LƯỢNG CÒN LẠI;

		FETCH NEXT FROM CUR INTO @BatchNo, @QtyInBatch, @UnitPrice;
	END
	CLOSE CUR;
	DEALLOCATE CUR;

END
